    10→// LLMModel represents a language model in the registry
    11→type LLMModel struct {
    12→	ID           string            `json:"id"`           // e.g., "gpt-4o-mini@2024-08-06"
    13→	Name         string            `json:"name"`         // Display name
    14→	Provider     string            `json:"provider"`     // openai, anthropic, azure, local
    15→	Version      string            `json:"version"`      // Model version
    16→	Capabilities []string          `json:"capabilities"` // ["code", "analysis", "planning"]
    17→	Config       map[string]string `json:"config"`       // Provider-specific config
    18→	MaxTokens    int               `json:"max_tokens"`   // Context window size
    19→	CostPerToken float64           `json:"cost_per_token,omitempty"`
    20→	Created      Time              `json:"created"`
    21→	Updated      Time              `json:"updated"`
    22→}
    23→
    24→// ValidProviders lists supported model providers
    25→var ValidProviders = []string{"openai", "anthropic", "azure", "local"}
    26→
    27→// ValidCapabilities lists supported model capabilities
    28→var ValidCapabilities = []string{"code", "analysis", "planning", "reasoning", "multimodal", "function_calling"}
    29→
    30→// ModelIDPattern matches valid model ID format: provider@version or provider/model@version
    31→var ModelIDPattern = regexp.MustCompile(`^[a-z0-9\-]+(@[a-z0-9\-\.]+)?$`)
    32→
    33→// Validate validates the LLM model data
    34→func (m *LLMModel) Validate() error {
    35→	// Required fields
    36→	if m.ID == "" {
    37→		return fmt.Errorf("model ID is required")
    38→	}
    39→	if m.Name == "" {
    40→		return fmt.Errorf("model name is required")
    41→	}
    42→	if m.Provider == "" {
    43→		return fmt.Errorf("model provider is required")
    44→	}
    45→	if len(m.Capabilities) == 0 {
    46→		return fmt.Errorf("at least one capability is required")
    47→	}
    48→
    49→	// Validate ID format
    50→	if !ModelIDPattern.MatchString(m.ID) {
    51→		return fmt.Errorf("invalid model ID format: %s (should match pattern: provider@version or provider/model@version)", m.ID)
    52→	}
    53→
    54→	// Validate provider
    55→	if !isValidProvider(m.Provider) {
    56→		return fmt.Errorf("invalid provider: %s (supported: %s)", m.Provider, strings.Join(ValidProviders, ", "))
    57→	}
    58→
    59→	// Validate capabilities
    60→	for _, capability := range m.Capabilities {
    61→		if !isValidCapability(capability) {
    62→			return fmt.Errorf("invalid capability: %s (supported: %s)", capability, strings.Join(ValidCapabilities, ", "))
    63→		}
    64→	}
    65→
    66→	// Validate numeric fields
    67→	if m.MaxTokens <= 0 {
    68→		return fmt.Errorf("max_tokens must be greater than 0")
    69→	}
    70→	if m.CostPerToken < 0 {
    71→		return fmt.Errorf("cost_per_token cannot be negative")
    72→	}
    73→
    74→	return nil
    75→}
    76→
    77→// SetSystemFields sets system-managed fields like timestamps
    78→func (m *LLMModel) SetSystemFields() {
    79→	now := Time(time.Now())
    80→	if time.Time(m.Created).IsZero() {
    81→		m.Created = now
    82→	}
    83→	m.Updated = now
    84→}
    85→
    86→// isValidProvider checks if the provider is in the allowed list
    87→func isValidProvider(provider string) bool {
    88→	for _, valid := range ValidProviders {
    89→		if provider == valid {
    90→			return true
    91→		}
    92→	}
    93→	return false
    94→}
    95→
    96→// isValidCapability checks if the capability is in the allowed list
    97→func isValidCapability(capability string) bool {
    98→	for _, valid := range ValidCapabilities {
    99→		if capability == valid {
   100→			return true
   101→		}
   102→	}
   103→	return false
   104→}
   105→
   106→// GetProviderFromID extracts the provider from the model ID
   107→func (m *LLMModel) GetProviderFromID() string {
   108→	if strings.Contains(m.ID, "@") {
   109→		parts := strings.Split(m.ID, "@")
   110→		if len(parts) > 0 {
   111→			// Handle cases like "gpt-4o-mini@2024-08-06" or "openai/gpt-4@v1"
   112→			providerPart := parts[0]
   113→			if strings.Contains(providerPart, "/") {
   114→				return strings.Split(providerPart, "/")[0]
   115→			}
   116→			return providerPart
   117→		}
   118→	}
   119→	// Fallback to the provider field
   120→	return m.Provider
   121→}
   122→
   123→// HasCapability checks if the model has a specific capability
   124→func (m *LLMModel) HasCapability(capability string) bool {
   125→	for _, cap := range m.Capabilities {
   126→		if cap == capability {
   127→			return true
   128→		}
   129→	}
   130→	return false
   131→}
